```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) const {
        // Write packet_id directly
        stream(packet_id);

        // Write username with length prefix
        stream & hexi::prefixed(username);

        // Write scores count first, then use operator<< for the vector
        stream << static_cast<uint32_t>(scores.size());
        stream << scores;

        // Write metadata as null-terminated string
        stream & hexi::null_terminated(metadata);
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    // Create buffer to hold serialized data
    std::vector<uint8_t> buffer;

    // Create adaptor and stream for the buffer
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Serialize the packet (calls packet.serialise(stream))
    stream & packet;

    return buffer;
}
```

The implementation:
1. **`serialise` method**: Serializes each field according to requirements:
   - `packet_id`: Written directly using `stream()`
   - `username`: Written with length prefix using `hexi::prefixed()`
   - `scores`: Count written manually, then vector written using `operator<<`
   - `metadata`: Written as null-terminated string using `hexi::null_terminated()`

2. **`serialize_packet` function**: Creates a buffer, wraps it with `buffer_adaptor` and `binary_stream`, then serializes the packet using the `&` operator which calls the `serialise` method.

