bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Calculate required space (header + size prefix + items)
    size_t required_space = sizeof(uint32_t) + sizeof(size_t) + items.size() * sizeof(uint32_t);

    // Check available space
    hexi::buffer_adaptor adaptor(buffer);
    if (buffer.size() + required_space > buffer.capacity()) {
        return false;  // Insufficient space
    }

    // Get write pointer (managed internally by adaptor)
    // Create binary stream for writing
    hexi::binary_stream stream(adaptor);

    // Write header
    stream.put(header);

    // Write container data
    stream.write_container(items);

    // Return true if write was successful
    return static_cast<bool>(stream);
}

