    BufferData<block_size> result;

    // Read header
    buffer.read(&result.header, sizeof(result.header));

    // Read data based on header size
    result.data.resize(result.header);
    if (result.header > 0) {
        buffer.read(result.data.data(), result.header);
    }

    return result;
