#include <hexi/static_buffer.h>
#include <vector>
#include <cstdint>

template<size_t buffer_size = 1024>
std::vector<uint8_t> preview_buffer_data(const hexi::static_buffer<std::byte, buffer_size>& buffer, size_t bytes_to_preview) {
    std::vector<uint8_t> result(bytes_to_preview);
    buffer.copy(result.data(), bytes_to_preview);
    return result;
}

test cases:
#include <gtest/gtest.h>
#include <hexi/static_buffer.h>
#include <vector>
#include <cstdint>

// Include the implementation
#include "implementation.hpp"

TEST(StaticBuffer, PreviewData) {
    hexi::static_buffer<std::byte, 1024> buffer;
    std::vector<uint8_t> test_data = {1, 2, 3, 4, 5, 6, 7, 8};
    buffer.write(test_data.data(), test_data.size());

    // Preview should not advance read pointer
    auto preview1 = preview_buffer_data(buffer, 3);
    auto preview2 = preview_buffer_data(buffer, 3);

    EXPECT_EQ(3, preview1.size());
    EXPECT_EQ(1, preview1[0]);
    EXPECT_EQ(2, preview1[1]);
    EXPECT_EQ(3, preview1[2]);

    // Both previews should be the same (read pointer not advanced)
    EXPECT_EQ(preview1, preview2);

    // Buffer size should remain unchanged
    EXPECT_EQ(test_data.size(), buffer.size());
}

TEST(StaticBuffer, PreviewAfterRead) {
    hexi::static_buffer<std::byte, 1024> buffer;
    std::vector<uint8_t> test_data = {10, 20, 30, 40, 50};
    buffer.write(test_data.data(), test_data.size());

    // Read some data
    std::vector<uint8_t> read_buf(2);
    buffer.read(read_buf.data(), 2);

    // Preview should start from current read position
    auto preview = preview_buffer_data(buffer, 2);

    EXPECT_EQ(2, preview.size());
    EXPECT_EQ(30, preview[0]);
    EXPECT_EQ(40, preview[1]);
}

