    // Read the byte array from buffer
    buffer.read(data, length);
}

struct BufferInfo {
    std::size_t size;
    std::size_t free_space;
};

BufferInfo get_buffer_info(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    BufferInfo info;

    // Get current size of the buffer
    info.size = buffer.size();

    // For a vector-backed buffer_adaptor, free_space represents available space
    // Since vector can dynamically grow, we set it to 0 to indicate no pre-allocated free space
    // (or the buffer will grow as needed)
    info.free_space = 0;

    return info;
