    // Two ranges overlap if: src_begin < dst_end AND dst_begin < src_end
    return src_begin < dst_end && dst_begin < src_end;
}

bool safe_memory_copy(void* destination, const void* source, std::size_t length) {
    // Check for overlap first
    if (check_regions_overlap(source, length, destination, length)) {
        return false;  // Overlap detected, not safe to copy with memcpy
    }

    // No overlap - safe to copy
    std::memcpy(destination, source, length);
    return true;
}
