TEST(PartialReadWrite, ReadWithSizeTracking) {
    std::vector<uint8_t> buffer = {10, 20, 30, 40, 50};
    std::vector<uint8_t> temp_buffer = buffer;
    hexi::pmc::buffer_read_adaptor read_adaptor(temp_buffer);

    // Check initial size
    EXPECT_EQ(5, read_adaptor.size());

    // Read 2 bytes
    uint8_t data[2];
    read_adaptor.read(data, 2);

    // Check remaining size
    EXPECT_EQ(3, read_adaptor.size());

    // Read remaining
    uint8_t remaining[3];
    read_adaptor.read(remaining, 3);

    // Check final size
    EXPECT_EQ(0, read_adaptor.size());
}

TEST(PartialReadWrite, WriteWithFreeTracking) {
    std::vector<uint8_t> buffer(100, 0);
    hexi::pmc::buffer_adaptor adaptor(buffer);

    // Check initial free space (calculate from buffer size and write offset)
    std::size_t initial_free = adaptor.buffer_write_adaptor<std::vector<uint8_t>>::free();
    EXPECT_EQ(0, initial_free); // buffer is full (100 bytes), write_offset is at 100

    // Write first chunk
    std::vector<uint8_t> chunk1 = {1, 2, 3};
    adaptor.write(chunk1.data(), chunk1.size());

    std::size_t free_after_first = adaptor.buffer_write_adaptor<std::vector<uint8_t>>::free();
    EXPECT_EQ(0, free_after_first); // For std::vector that auto-grows, free() is always 0 after write

    // Write second chunk
    std::vector<uint8_t> chunk2 = {4, 5};
    adaptor.write(chunk2.data(), chunk2.size());

    std::size_t free_after_second = adaptor.buffer_write_adaptor<std::vector<uint8_t>>::free();
    EXPECT_EQ(0, free_after_second); // For std::vector that auto-grows, free() is always 0 after write
}

