#include <hexi/pmc/buffer_read_adaptor.h>
#include <vector>
#include <cstdint>
#include <cstring>

struct Header {
    uint32_t magic;
    uint16_t version;
};

Header peek_header_without_reading(const std::vector<uint8_t>& buffer) {
    // Create a buffer adaptor from the input vector
    hexi::pmc::buffer_read_adaptor adaptor(buffer);

    Header header;

    // Use copy() to peek at header without advancing read cursor
    // This reads the data but doesn't consume it from the buffer
    adaptor.copy(&header, sizeof(Header));

    // Use read_ptr() to verify pointer position
    // The pointer should still be at the beginning since copy() doesn't advance the cursor
    const std::byte* ptr = adaptor.read_ptr();

    // We can verify that the pointer is at the start by comparing with buffer data
    // ptr points to buffer[0] since we haven't consumed any data

    return header;
}

std::vector<uint8_t> peek_then_conditionally_read(const std::vector<uint8_t>& buffer) {
    // Create a buffer adaptor from the input vector
    hexi::pmc::buffer_read_adaptor adaptor(buffer);

    std::vector<uint8_t> result;

    if (adaptor.size() == 0) {
        return result;
    }

    // Use copy() to peek at first byte without consuming it
    uint8_t first_byte;
    adaptor.copy(&first_byte, sizeof(uint8_t));

    // Based on the peeked value, decide whether to read more data
    // Condition: if first byte >= 128, read 4 bytes, otherwise read 1 byte
    if (first_byte >= 128) {
        // Condition met - use read() to consume 4 bytes from buffer
        std::size_t bytes_to_read = std::min(static_cast<std::size_t>(4), adaptor.size());
        result.resize(bytes_to_read);
        adaptor.read(result.data(), bytes_to_read);
    } else {
        // Condition not met - use read() to consume only 1 byte from buffer
        result.resize(1);
        adaptor.read(result.data(), 1);
    }

    return result;
}
```

**Key differences between `copy()` and `read()`:**

1. **`copy()`**: Peeks at data without advancing the read cursor. You can call it multiple times and get the same data.

2. **`read()`**: Actually consumes the data and advances the read cursor. Subsequent reads will get different data.

3. **`read_ptr()`**: Returns a pointer to the current read position in the buffer, useful for verification that the cursor hasn't moved after `copy()` operations.

